#include <stdio.h>
#define MOD 1000000007
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n, k;
        scanf("%d %d", &n, &k);
        long long dp[n + 1];
        dp[0] = 1;
        for (int i = 1; i <= n; i++) {
            if (i < k) {
                dp[i] = (dp[i - 1] * 2) % MOD;
            } else {
                dp[i] = (dp[i - 1] + dp[i - k]) % MOD;
            }
        }
        printf("%lld\n", dp[n]);
    }
    return 0;
}

